int longestCommonSubsequence(String text1, String text2) {
  int m = text1.length;
  int n = text2.length;

  // dp[i][j] = LCS length for text1[0..i-1] and text2[0..j-1]
  List<List<int>> dp = List.generate(
    m + 1,
    (_) => List.filled(n + 1, 0),
  );

  for (int i = 1; i <= m; i++) {
    for (int j = 1; j <= n; j++) {
      if (text1[i - 1] == text2[j - 1]) {
        dp[i][j] = dp[i - 1][j - 1] + 1;
      } else {
        dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
      }
    }
  }

  return dp[m][n];
}

